module two_bit_counter(  
    input clk,  
    input rst,  
    output reg [1:0] count  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin  
        if (rst)  
            count <= 2'b00;  
        else  
            count <= count + 1;  
    end  
endmodule
